import{_ as a,o as n,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const r="/images/schrift001.jpg",s="/images/schrift002.jpg",c="/images/schrift003.jpg",m=JSON.parse('{"title":"Devanāgarī = देवनागरी","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/schrift01.md","filePath":"lektionen/schrift01.md"}'),p={name:"lektionen/schrift01.md"};function o(h,e,u,l,d,k){return n(),i("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="devanagari-देवनागरी" tabindex="-1">Devanāgarī = देवनागरी <a class="header-anchor" href="#devanagari-देवनागरी" aria-label="Permalink to &quot;Devanāgarī = देवनागरी&quot;">​</a></h1><h2 id="schriftubung-1" tabindex="-1">Schriftübung 1 <a class="header-anchor" href="#schriftubung-1" aria-label="Permalink to &quot;Schriftübung 1&quot;">​</a></h2><p>Sanskrit wurde und wird in einer Vielzahl von Schriften geschrieben. Folgende Übersicht gibt einen kleinen Ausschnitt aus diesen Schriften:</p><p><img src="'+r+'" alt=""><br> Abb.: Schriftproben Sanskrit<br> [Bildquelle: Wikipedia, GNU FD LIzenz]</p><p>Die wichtigste moderne nordindische Sanskritschrift ist die Devanāgarī:</p><p><img src="'+s+'" alt=""></p><p>Jedes Konsonantenzeichen bezeichnet ein auf den Konsonanten folgendes &quot;a&quot; mit. Soll der reine Konsonant geschrieben werden (ohne nachfolgenden Vokal), muss man dies durch einen untergesetzten Schrägstrich -- virāma = विराम -- kennzeichnen:</p><p>क् = k, च् = c, ट् = ṭ, त्  = t, प् = p</p><p>Auf einen Konsonanten folgende Vokale -- außer &quot;a&quot; -- werden so geschrieben:</p><p>का = kā, कि = ki, की = kī, कु = ku, कू = kū, कृ = kṛ, कॄ = kṝ, कॢ  = kḷ</p><p>के = ke, कै = kai, को = ko, कौ = kau</p><p>Die Reihenfolge beim Schreiben dieser Verbindungen von Konsonant + Vokal ist:</p><p><img src="'+c+'" alt=""></p><p>Beim Schreiben wird jeder Buchstabe inklusive Querstrich an Oberlinie vollendet bevor der nächste Buchstabe geschrieben wird.</p><h2 id="ubung" tabindex="-1">Übung <a class="header-anchor" href="#ubung" aria-label="Permalink to &quot;Übung&quot;">​</a></h2><p>Schreiben Sie in Devanāgarī:</p><p>kaka kāka kapa kapi kaṭa kuṭi tap tac cāpa kṛta caita cūta pat pitā pīta puta cātu cāti ṭīkā ṭāka ṭoṭa tepa tṛta kḷp kopa kaupa poka peta tṝ pṝ pṛc pat pati capeṭā</p><p>Lesen und transliterieren Sie:</p><p>तॄ पाप चट् चि चाप पॄ पति पितृ कॢप् कृ कुप् कुतो चैक पुट पचति तौ पू चेत् पतति ततो तट तपति तु ते कृ पीतौ</p><p>Zusätzliche Leseübung:</p><p>पिता Vater, कपि Affe, कृत getan,  टीका Subkommentar, तत् dieses, तट Ufer, पत् dahinschießen, पट Gewebe, काच Glas,  काकुत् Gaumen, चित् wahrnehmen, पृच् mischen,  पोटक Knecht, चेतु Absicht, तौतातित Anhänger des Kumārila (Mīmāṃsā), तूत Maulbeerbaum, पीत getrunken,  पीति Trank, कॢप्  passen, कृपते er jammert, पुटी Falte, चापि desgleichen, तोक Nachkommenschaft, तृपत् satt, पॄ füllen, कृकाटी Halsgelenk, पूपौ zwei Kuchen, पैतृकी väterlich (fem.), कौट betrügerisch, कच Haupthaar, कुतपे auf der Ziegenhaardecke, कुचौ Busen, चकिता erschrocken (fem.)</p>',22)])])}const b=a(p,[["render",o]]);export{m as __pageData,b as default};
